# Tracking plan configuration — stored as structured data for programmatic access
tracking_plan = {
    "integration": "contract-review-assistant",
    "north_star": {
        "name": "contract_cycle_time_days",
        "definition": "Calendar days from contract receipt email timestamp to digital signature timestamp",
        "direction": "lower_is_better",
        "baseline": 12.4,  # days, 4-week pre-go-live average
        "target": 7.5,     # days, target by 90 days post go-live
        "minimum_bar": 11.0,  # days — above this triggers regression review
        "data_source": "contract_management_system.contracts",
        "fields": ["received_at", "signed_at"],
        "time_window": "rolling_30_days",
        "exclusions": ["template_contracts", "internal_renewals"],
        "reporting_cadence": "weekly",
        "report_owner": "operations_analyst",
    },
    "supporting_metrics": [
        {
            "name": "first_review_time_hours",
            "definition": "Hours from contract receipt to completion of first AI review pass",
            "direction": "lower_is_better",
            "target": 0.5,  # 30 minutes
            "data_source": "claude_integration_logs.review_completed_events",
        },
        {
            "name": "revision_cycle_rate",
            "definition": "Percentage of contracts requiring one or more revision cycles after first AI review",
            "direction": "lower_is_better",
            "target": 0.15,  # 15%
            "data_source": "contract_management_system.revision_events",
        },
        {
            "name": "issue_identification_recall",
            "definition": "Percentage of material contract issues identified by AI, validated on monthly sample",
            "direction": "higher_is_better",
            "target": 0.88,  # 88% — target quality bar from eval framework
            "data_source": "monthly_human_eval",
        },
    ],
    "guard_rails": [
        {
            "name": "api_availability",
            "minimum": 0.995,  # 99.5%
            "alert_threshold": 0.990,
        },
        {
            "name": "cost_per_contract_usd",
            "maximum": 2.50,
            "alert_threshold": 2.00,  # alert at 80% of maximum
        },
        {
            "name": "critical_issue_miss_rate",
            "maximum": 0.02,  # 2% — critical issues cannot be missed more than 2% of the time
            "alert_threshold": 0.01,
        },
    ],
    "alerts": {
        "north_star_regression": {
            "condition": "rolling_30d_mean > minimum_bar",
            "notify": ["programme_lead", "bu_lead"],
            "response_time_hours": 24,
        },
        "guard_rail_breach": {
            "condition": "any guard rail breaches its maximum/minimum",
            "notify": ["programme_lead", "bu_lead", "sponsor"],
            "response_time_hours": 4,
        },
    }
}
